package com.example.pametnipaketnik

import android.os.Bundle
import android.util.Log
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.Column
import androidx.compose.material3.Button
import androidx.compose.material3.Text
import com.example.pametnipaketnik.ui.theme.PametniPaketnikTheme

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            PametniPaketnikTheme {
                Column {
                    Button(onClick = {
                        //Token za id 1965 iz postman
                        val testBase64=""
                        proccesAndPlay(this@MainActivity, testBase64)
                    }) {

                        Text("Predvajaj žeton")
                    }
                }
            }
        }
    }

    fun proccesAndPlay(context: android.content.Context, base64Data: String) {
        val cleanBase64 = base64Data.replace("\\s".toRegex(), "")
            .replace("\"", "")

        Log.d("D4M", "Dolžina očiščenega niza: ${cleanBase64.length}")

        try {
            val bytes = android.util.Base64.decode(cleanBase64, android.util.Base64.DEFAULT)
            Log.d("D4M", "Base64 uspešno dekodiran v bajte.")

            val inputStream = java.util.zip.GZIPInputStream(bytes.inputStream())

            val tempFile = java.io.File(context.cacheDir, "token.wav")
            java.io.FileOutputStream(tempFile).use { output ->
                inputStream.copyTo(output)
            }
            inputStream.close()
            Log.d("D4M", "Datoteka token.wav je ustvarjena na poti: ${tempFile.absolutePath}")

            android.media.MediaPlayer().apply {
                setDataSource(tempFile.absolutePath)
                prepare()
                start()
                Log.d("D4M", "Predvajanje se je začelo!")
                setOnCompletionListener { it.release() }
            }
        } catch (e: Exception) {
            Log.e("D4M", "Napaka pri obdelavi: ${e.message}")
            e.printStackTrace()
        }
    }
}
